// Rate Limiter untuk 900 Siswa - Prevent Server Overload
window.RateLimiter={_syncQueue:[],_processing:!1,_maxConcurrent:10,_requestsPerSecond:10,_lastRequestTime:0,_jitterMap:{},addToQueue:function(e,t){const i=Math.random().toString(36).substring(7);this._jitterMap[i]={examId:e,callback:t,timestamp:Date.now()};const n=Math.floor(120*Math.random());return this._syncQueue.push({id:i,examId:e,callback:t,jitterDelay:n,addedAt:Date.now()}),console.log(`[RateLimiter] Added to queue: ${e} (jitter: ${n}s, queue size: ${this._syncQueue.length})`),this._processQueue(),i},_processQueue:function(){if(this._processing||0===this._syncQueue.length)return;this._processing=!0;const e=this._syncQueue.shift();if(!e)return void(this._processing=!1);const t=Date.now()-this._lastRequestTime,i=1e3/this._requestsPerSecond;let n=Math.max(0,i-t)+1e3*e.jitterDelay;console.log(`[RateLimiter] Processing: ${e.examId} (delay: ${n}ms, queue: ${this._syncQueue.length})`),setTimeout(()=>{try{e.callback&&e.callback()}catch(e){console.error("[RateLimiter] Callback error:",e)}this._lastRequestTime=Date.now(),this._processing=!1,this._processQueue()},n)},getQueueStatus:function(){return{queueSize:this._syncQueue.length,processing:this._processing,lastRequestTime:this._lastRequestTime}},clearQueue:function(){this._syncQueue=[],this._jitterMap={},this._processing=!1,console.log("[RateLimiter] Queue cleared")}},window.syncWithRateLimit=function(e,t){return new Promise((i,n)=>{window.RateLimiter.addToQueue(e,async()=>{try{const n=await t();i(n)}catch(e){n(e)}})})};
